/**
 * Agent orchestration types and interfaces for the AI Engineering System.
 * Defines the core abstractions for agent coordination and execution.
 */

import type { Decision, Task } from "../context/types";

/**
 * Represents different types of agents available in the system
 */
export enum AgentType {
    // Architecture & Planning
    ARCHITECT_ADVISOR = "architect-advisor",
    BACKEND_ARCHITECT = "backend-architect",
    INFRASTRUCTURE_BUILDER = "infrastructure-builder",

    // Development & Coding
    FRONTEND_REVIEWER = "frontend-reviewer",
    FULL_STACK_DEVELOPER = "full-stack-developer",
    API_BUILDER_ENHANCED = "api-builder-enhanced",
    DATABASE_OPTIMIZER = "database-optimizer",
    JAVA_PRO = "java-pro",

    // Quality & Testing
    CODE_REVIEWER = "code-reviewer",
    TEST_GENERATOR = "test-generator",
    SECURITY_SCANNER = "security-scanner",
    PERFORMANCE_ENGINEER = "performance-engineer",

    // DevOps & Deployment
    DEPLOYMENT_ENGINEER = "deployment-engineer",
    MONITORING_EXPERT = "monitoring-expert",
    COST_OPTIMIZER = "cost-optimizer",

    // AI & Machine Learning
    AI_ENGINEER = "ai-engineer",
    ML_ENGINEER = "ml-engineer",

    // Content & SEO
    SEO_SPECIALIST = "seo-specialist",
    PROMPT_OPTIMIZER = "prompt-optimizer",

    // Plugin Development
    AGENT_CREATOR = "agent-creator",
    COMMAND_CREATOR = "command-creator",
    SKILL_CREATOR = "skill-creator",
    TOOL_CREATOR = "tool-creator",
    PLUGIN_VALIDATOR = "plugin-validator",
}

/**
 * Execution strategies for agent coordination
 */
export enum ExecutionStrategy {
    PARALLEL = "parallel",
    SEQUENTIAL = "sequential",
    CONDITIONAL = "conditional",
}

/**
 * Confidence level for agent results
 */
export enum ConfidenceLevel {
    LOW = "low",
    MEDIUM = "medium",
    HIGH = "high",
    VERY_HIGH = "very_high",
}

/**
 * Base interface for all agent inputs
 */
export interface AgentInput {
    type: AgentType;
    context: Record<string, unknown>;
    parameters?: Record<string, unknown>;
    timeout?: number;
}

/**
 * Base interface for all agent outputs
 */
export interface AgentOutput {
    type: AgentType;
    success: boolean;
    result: Record<string, unknown>;
    confidence: ConfidenceLevel;
    reasoning?: string;
    executionTime: number;
    error?: string;
}

/**
 * Represents a single agent task in an execution plan
 */
export interface AgentTask {
    id: string;
    type: AgentType;
    name: string;
    description: string;
    input: AgentInput;
    strategy: ExecutionStrategy;
    /** Optional command for compatibility with Task interface */
    command?: string;
    dependsOn?: string[];
    timeout?: number;
    retry?: {
        maxAttempts: number;
        delay: number;
        backoffMultiplier: number;
    };
}

/**
 * Result of executing an agent task
 */
export interface AgentTaskResult {
    id: string;
    type: AgentType;
    status: AgentTaskStatus;
    output?: AgentOutput;
    executionTime: number;
    startTime: Date;
    endTime: Date;
    error?: string;
}

/**
 * Status of an agent task
 */
export enum AgentTaskStatus {
    PENDING = "pending",
    RUNNING = "running",
    COMPLETED = "completed",
    FAILED = "failed",
    TIMEOUT = "timeout",
    SKIPPED = "skipped",
}

/**
 * Configuration for agent coordination
 */
export interface AgentCoordinatorConfig {
    maxConcurrency: number;
    defaultTimeout: number;
    retryAttempts: number;
    retryDelay: number;
    enableCaching: boolean;
    logLevel: "debug" | "info" | "warn" | "error";
}

/**
 * Result aggregation strategy
 */
export interface AggregationStrategy {
    type:
        | "merge"
        | "vote"
        | "weighted"
        | "priority"
        | "parallel"
        | "sequential";
    weights?: Partial<Record<AgentType, number>>;
    priority?: AgentType[];
    conflictResolution?: "highest_confidence" | "most_recent" | "manual";
}

/**
 * Plan generation specific types
 */
export interface PlanGenerationInput {
    description: string;
    scope?: string;
    requirements?: string[];
    constraints?: string[];
    context?: Record<string, unknown>;
}

export interface PlanGenerationOutput {
    plan: {
        name: string;
        description: string;
        tasks: AgentTask[];
        dependencies: string[][];
    };
    confidence: ConfidenceLevel;
    reasoning: string;
    suggestions: string[];
}

/**
 * Code review specific types
 */
export interface CodeReviewInput {
    files: string[];
    reviewType: "full" | "incremental" | "security" | "performance";
    severity: "low" | "medium" | "high" | "critical";
    context?: Record<string, unknown>;
}

export interface CodeReviewFinding {
    file: string;
    line: number;
    severity: "low" | "medium" | "high" | "critical";
    category: string;
    message: string;
    suggestion?: string;
    confidence: ConfidenceLevel;
    agent?: string;
}

export interface CodeReviewOutput {
    findings: CodeReviewFinding[];
    summary: {
        total: number;
        bySeverity: Record<string, number>;
        byCategory: Record<string, number>;
    };
    recommendations: string[];
    overallScore: number; // 0-100
}

/**
 * Agent execution context
 */
export interface AgentExecutionContext {
    planId: string;
    taskId: string;
    workingDirectory: string;
    environment: Record<string, string>;
    metadata: Record<string, unknown>;
}

/**
 * Event types for agent coordination
 */
export interface AgentEvent {
    type:
        | "task_started"
        | "task_completed"
        | "task_failed"
        | "task_timeout"
        | "aggregation_started"
        | "aggregation_completed";
    taskId: string;
    agentType: AgentType;
    timestamp: Date;
    data?: Record<string, unknown>;
}

/**
 * Progress tracking for agent orchestration
 */
export interface AgentProgress {
    totalTasks: number;
    completedTasks: number;
    failedTasks: number;
    runningTasks: number;
    currentTask?: string;
    estimatedTimeRemaining?: number;
    percentageComplete: number;
}

/**
 * Error handling types
 */
export interface AgentError {
    taskId: string;
    agentType: AgentType;
    error: string;
    recoverable: boolean;
    suggestedAction?: string;
    timestamp: Date;
}

/**
 * Performance metrics for agent execution
 */
export interface AgentMetrics {
    agentType: AgentType;
    executionCount: number;
    averageExecutionTime: number;
    successRate: number;
    averageConfidence: number;
    lastExecutionTime: Date;
}

/**
 * Agent definition loaded from .claude-plugin/agents/
 */
export interface AgentDefinition {
    type: AgentType;
    name: string;
    description: string;
    mode: "subagent" | "tool";
    temperature: number;
    capabilities: string[];
    handoffs: AgentType[];
    tags: string[];
    category: string;
    tools: {
        read: boolean;
        grep: boolean;
        glob: boolean;
        list: boolean;
        bash: boolean;
        edit: boolean;
        write: boolean;
        patch: boolean;
    };
    promptPath: string;
    prompt: string;
}

/**
 * Agent execution record for persistence
 */
export interface AgentExecution {
    taskId: string;
    agentType: AgentType;
    input?: Record<string, unknown>;
    output?: Record<string, unknown>;
    success: boolean;
    confidence?: ConfidenceLevel;
    executionTime: number;
    timestamp: Date;
    error?: string;
}

/**
 * Improvement record for self-improvement system
 */
export interface ImprovementRecord {
    id: string;
    type: "agent_prompt" | "capability" | "handoff" | "workflow";
    target: AgentType | string;
    description: string;
    evidence: string[];
    suggestedAt: Date;
    implementedAt?: Date;
    effectivenessScore?: number;
}

/**
 * Handoff record for inter-agent communication
 */
export interface HandoffRecord {
    id: string;
    fromAgent: AgentType;
    toAgent: AgentType;
    reason: string;
    context?: Record<string, unknown>;
    success: boolean;
    timestamp: Date;
}

/**
 * Execution mode for hybrid Task tool + local execution
 */
export type ExecutionMode = "task-tool" | "local" | "hybrid";

