/**
 * Core agent coordination engine for the AI Engineering System.
 * Handles agent orchestration, execution strategies, and result aggregation.
 */

import { EventEmitter } from "node:events";
import { ExecutorBridge } from "./executor-bridge";
import { AgentRegistry } from "./registry";
import {
    type AgentCoordinatorConfig,
    AgentError,
    type AgentEvent,
    AgentInput,
    type AgentMetrics,
    type AgentOutput,
    type AgentProgress,
    type AgentTask,
    type AgentTaskResult,
    AgentTaskStatus,
    AgentType,
    type AggregationStrategy,
    ConfidenceLevel,
    ExecutionStrategy,
} from "./types";

export class AgentCoordinator extends EventEmitter {
    private config: AgentCoordinatorConfig;
    private runningTasks: Map<string, AgentTask> = new Map();
    private completedTasks: Map<string, AgentTaskResult> = new Map();
    private metrics: Map<AgentType, AgentMetrics> = new Map();
    private cache: Map<string, AgentOutput> = new Map();
    private registry: AgentRegistry;
    private executorBridge: ExecutorBridge;

    constructor(config: AgentCoordinatorConfig, registry?: AgentRegistry) {
        super();
        this.config = config;
        this.registry = registry || new AgentRegistry();
        this.executorBridge = new ExecutorBridge(this.registry);
        this.initializeMetrics();
    }

    /**
     * Execute a collection of agent tasks with the specified strategy
     */
    public async executeTasks(
        tasks: AgentTask[],
        strategy: AggregationStrategy,
    ): Promise<AgentTaskResult[]> {
        this.emit("execution_started", { taskCount: tasks.length });

        try {
            // Sort tasks by dependencies
            const sortedTasks = this.resolveDependencies(tasks);
            const results: AgentTaskResult[] = [];

            // Execute tasks based on strategy
            if (strategy.type === "parallel") {
                const parallelResults = await this.executeParallel(sortedTasks);
                results.push(...parallelResults);
            } else if (strategy.type === "sequential") {
                const sequentialResults =
                    await this.executeSequential(sortedTasks);
                results.push(...sequentialResults);
            } else {
                // Conditional execution - evaluate conditions first
                const conditionalResults = await this.executeConditional(
                    sortedTasks,
                    strategy,
                );
                results.push(...conditionalResults);
            }

            // Aggregate results
            const aggregatedResults = this.aggregateResults(results, strategy);

            // Keep completed tasks so progress can be inspected after execution.
            // Call reset() when you want to clear state between runs.

            this.emit("execution_completed", { results: aggregatedResults });
            return aggregatedResults;
        } catch (error) {
            this.emit("execution_failed", {
                error: error instanceof Error ? error.message : "Unknown error",
            });
            throw error;
        }
    }

    /**
     * Execute a single agent task
     */
    public async executeTask(task: AgentTask): Promise<AgentTaskResult> {
        const startTime = new Date();

        // Check if already running
        if (this.runningTasks.has(task.id)) {
            throw new Error(`Task ${task.id} is already running`);
        }

        // Check cache if enabled
        if (this.config.enableCaching) {
            const cacheKey = this.generateCacheKey(task);
            const cached = this.cache.get(cacheKey);
            if (cached) {
                const result: AgentTaskResult = {
                    id: task.id,
                    type: task.type,
                    status: AgentTaskStatus.COMPLETED,
                    output: cached,
                    executionTime: 0,
                    startTime,
                    endTime: new Date(),
                };
                this.emit("task_cached", {
                    taskId: task.id,
                    agentType: task.type,
                });
                return result;
            }
        }

        this.runningTasks.set(task.id, task);
        this.emitEvent("task_started", task.id, task.type);

        try {
            // Check dependencies
            await this.checkTaskDependencies(task);

            // Execute the agent
            // Apply coordinator-level default timeout as an upper bound.
            const effectiveTimeout = task.timeout ?? this.config.defaultTimeout;
            const coordinatorTask: AgentTask = {
                ...task,
                // If a task provided timeout is longer than coordinator default, clamp it.
                timeout: Math.min(effectiveTimeout, this.config.defaultTimeout),
            };

            // Always pass the task with effective timeout to the executor bridge
            const output = await this.executeAgent(coordinatorTask);

            // Update metrics
            this.updateMetrics(task.type, output, true);

            const result: AgentTaskResult = {
                id: task.id,
                type: task.type,
                status: AgentTaskStatus.COMPLETED,
                output,
                executionTime: new Date().getTime() - startTime.getTime(),
                startTime,
                endTime: new Date(),
            };

            // Cache result if enabled
            if (this.config.enableCaching && output.success) {
                const cacheKey = this.generateCacheKey(task);
                this.cache.set(cacheKey, output);
            }

            this.completedTasks.set(task.id, result);
            this.runningTasks.delete(task.id);
            this.emitEvent("task_completed", task.id, task.type, { output });

            return result;
        } catch (error) {
            const errorMessage =
                error instanceof Error ? error.message : "Unknown error";

            // Update metrics
            this.updateMetrics(task.type, undefined, false);

            // Handle retry logic
            if (task.retry && this.shouldRetry(task, errorMessage)) {
                this.log(
                    `Retrying task ${task.id} after error: ${errorMessage}`,
                );
                await this.sleep(task.retry.delay * 1000);
                return this.executeTask(task);
            }

            const result: AgentTaskResult = {
                id: task.id,
                type: task.type,
                status: AgentTaskStatus.FAILED,
                executionTime: new Date().getTime() - startTime.getTime(),
                startTime,
                endTime: new Date(),
                error: errorMessage,
            };

            this.completedTasks.set(task.id, result);
            this.runningTasks.delete(task.id);
            this.emitEvent("task_failed", task.id, task.type, {
                error: errorMessage,
            });

            return result;
        }
    }

    /**
     * Get current execution progress
     */
    public getProgress(): AgentProgress {
        const totalTasks = this.runningTasks.size + this.completedTasks.size;
