            (r) => r.status === AgentTaskStatus.COMPLETED,
        ).length;
        const failedTasks = Array.from(this.completedTasks.values()).filter(
            (r) => r.status === AgentTaskStatus.FAILED,
        ).length;
        const runningTasks = this.runningTasks.size;

