import { afterEach, beforeEach, describe, expect, it } from "bun:test";
import { AgentCoordinator } from "../../src/agents/coordinator";
import {
    type AgentCoordinatorConfig,
    type AgentTask,
    AgentTaskStatus,
    AgentType,
    AggregationStrategy,
    ConfidenceLevel,
    ExecutionStrategy,
} from "../../src/agents/types";

describe("AgentCoordinator", () => {
    let coordinator: AgentCoordinator;
    let config: AgentCoordinatorConfig;

    beforeEach(() => {
        config = {
            maxConcurrency: 3,
            defaultTimeout: 5000,
            retryAttempts: 2,
            retryDelay: 100,
            enableCaching: true,
            logLevel: "error",
        };
        coordinator = new AgentCoordinator(config);
    });

    afterEach(() => {
        coordinator.reset();
    });

    describe("Task Execution", () => {
        it("should execute a single task successfully", async () => {
            const task: AgentTask = {
                id: "test-1",
                type: AgentType.CODE_REVIEWER,
                name: "Test Code Review",
                description: "Test task",
                input: {
                    type: AgentType.CODE_REVIEWER,
                    context: { files: ["test.js"] },
                },
                strategy: ExecutionStrategy.SEQUENTIAL,
            };

            const result = await coordinator.executeTask(task);

